import{c as a,Q as o,j as t,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Claude Code — claude.com/blog","description":"","frontmatter":{"title":"Claude Code — claude.com/blog","type":"index"},"headers":[],"relativePath":"research/claude-blog/claude-code/index.md","filePath":"research/claude-blog/claude-code/index.md","lastUpdated":1779935873000}'),i={name:"research/claude-blog/claude-code/index.md"};function l(n,e,s,d,u,c){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="claude-code-—-claude-com-blog" tabindex="-1">Claude Code — claude.com/blog <a class="header-anchor" href="#claude-code-—-claude-com-blog" aria-label="Permalink to &quot;Claude Code — claude.com/blog&quot;">​</a></h1><blockquote><p>收錄自 <a href="https://claude.com/blog/category/claude-code" target="_blank" rel="noreferrer">claude.com/blog/category/claude-code</a> · 20 篇文章 · 2026-01-29 ~ 2026-05-14 最後更新：2026-05-16</p></blockquote><hr><h2 id="the-founder-s-playbook-building-an-ai-native-startup" tabindex="-1">The founder&#39;s playbook: Building an AI-native startup <a class="header-anchor" href="#the-founder-s-playbook-building-an-ai-native-startup" aria-label="Permalink to &quot;The founder&#39;s playbook: Building an AI-native startup&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-14 | <strong>URL:</strong> <a href="https://claude.com/blog/the-founders-playbook" target="_blank" rel="noreferrer">https://claude.com/blog/the-founders-playbook</a></p><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>重構新創公司生命週期（Idea → MVP → Launch → Scale）以反映 AI 原生開發能力。涵蓋如何用 Claude 驗證假設、規劃架構、防止技術債，以及以 Agentic Workflow 取代創辦人注意力。</p><h3 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>以 Claude 驗證問題假設、進行競品分析和用戶訪談</li><li>架構與安全實踐防止 AI 生成代碼的技術債</li><li>Launch 階段：以 Agentic Workflow 取代重複性創辦人操作</li><li>案例：Ambral、Anything、Carta Healthcare、HumanLayer、Vulcan Technologies</li><li>產品矩陣：Chat vs Claude Cowork vs Claude Code 適用場景</li></ul><hr><h2 id="how-anthropic-s-cybersecurity-team-built-a-threat-detection-platform-with-claude-code" tabindex="-1">How Anthropic&#39;s cybersecurity team built a threat detection platform with Claude Code <a class="header-anchor" href="#how-anthropic-s-cybersecurity-team-built-a-threat-detection-platform-with-claude-code" aria-label="Permalink to &quot;How Anthropic&#39;s cybersecurity team built a threat detection platform with Claude Code&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-12 | <strong>URL:</strong> <a href="https://claude.com/blog/how-anthropic-uses-claude-cybersecurity" target="_blank" rel="noreferrer">https://claude.com/blog/how-anthropic-uses-claude-cybersecurity</a></p><h3 id="summary-1" tabindex="-1">Summary <a class="header-anchor" href="#summary-1" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Jackie Bow（Detection Platform Engineering）打造 CLUE（Claude Looks Up Evidence）平台，自動化安全告警分類與威脅調查。30 天內自動化 12,000 次查詢，節省約 1,870 小時人工操作。</p><h3 id="key-points-1" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-1" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>CLUE Triage：整合 Slack、文件、code repo、數據倉庫，偽陽性從 33% 降至 7%</li><li>CLUE Investigate：自然語言查詢安全日誌，Claude 平行執行 SQL，3-4 分鐘完成原本需數小時的工作</li><li>30 天：12,000 次查詢自動化、27,000 次工具呼叫、節省約 1,870 人工小時</li><li>5-10x 時間節省比人工操作</li><li>未來方向：主動威脅獵捕、調查記錄組織記憶、非確定性調查路徑</li></ul><hr><h2 id="how-a-non-technical-project-manager-built-and-shipped-a-stress-management-app-with-claude-code-in-six-weeks" tabindex="-1">How a non-technical project manager built and shipped a stress management app with Claude Code in six weeks <a class="header-anchor" href="#how-a-non-technical-project-manager-built-and-shipped-a-stress-management-app-with-claude-code-in-six-weeks" aria-label="Permalink to &quot;How a non-technical project manager built and shipped a stress management app with Claude Code in six weeks&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-01 | <strong>URL:</strong> <a href="https://claude.com/blog/how-a-non-technical-project-manager-built-and-shipped-a-stress-management-app-with-claude-code-in-six-weeks" target="_blank" rel="noreferrer">https://claude.com/blog/how-a-non-technical-project-manager-built-and-shipped-a-stress-management-app-with-claude-code-in-six-weeks</a></p><h3 id="summary-2" tabindex="-1">Summary <a class="header-anchor" href="#summary-2" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Kostiantyn Vlasenko（PM，零編碼背景）在六週內用 Claude Code 建立並上架 iOS 壓力管理 App Respiro。採用 15+ 個專業 Subagent 並行架構，印證 PM 式管理 Agent 的可行性。</p><h3 id="key-points-2" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-2" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>TCA 架構師 Agent、Swift 開發 Agent、Metal 專家、Code Reviewer 並行工作</li><li>從 React Native 轉 Swift 只需幾小時（Claude vision 協助截圖分析）</li><li>Claude 協助整合 analytics、追蹤用戶漏斗、行銷內容、成長策略</li><li>核心洞察：「管理 Agent 就像管理真實的人一樣」</li><li>現已上架 App Store，吸引數百名用戶</li></ul><hr><h2 id="lessons-from-building-claude-code-prompt-caching-is-everything" tabindex="-1">Lessons from building Claude Code: Prompt caching is everything <a class="header-anchor" href="#lessons-from-building-claude-code-prompt-caching-is-everything" aria-label="Permalink to &quot;Lessons from building Claude Code: Prompt caching is everything&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-30 | <strong>URL:</strong> <a href="https://claude.com/blog/lessons-from-building-claude-code-prompt-caching-is-everything" target="_blank" rel="noreferrer">https://claude.com/blog/lessons-from-building-claude-code-prompt-caching-is-everything</a></p><h3 id="summary-3" tabindex="-1">Summary <a class="header-anchor" href="#summary-3" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Thariq Shihipar 分享 Claude Code 團隊的 Prompt Caching 最佳實踐。Cache hit rate 被視為關鍵指標，下降時會觸發 incident 處理。靜態到動態的分層結構是最有效的快取策略。</p><h3 id="key-points-3" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-3" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>分層結構（靜態到動態）：system prompt + tools → 專案檔案 → session context → 對話訊息</li><li>用 messages 代替更新 system prompt（保護快取前綴）；用 <code>&lt;system-reminder&gt;</code> 標籤傳遞更新資訊</li><li>Mid-session 禁止切換模型（快取模型專屬，切換須重建整個快取）</li><li>工具管理：對話中不增刪工具；用 stub + <code>defer_loading: true</code> 保持前綴穩定</li><li>Compact 時保留相同 system prompt + tools + user context（確保前綴匹配）</li></ul><hr><h2 id="onboarding-claude-code-like-a-new-developer-lessons-from-17-years-of-development" tabindex="-1">Onboarding Claude Code like a new developer: Lessons from 17 years of development <a class="header-anchor" href="#onboarding-claude-code-like-a-new-developer-lessons-from-17-years-of-development" aria-label="Permalink to &quot;Onboarding Claude Code like a new developer: Lessons from 17 years of development&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-28 | <strong>URL:</strong> <a href="https://claude.com/blog/onboarding-claude-code-like-a-new-developer-lessons-from-17-years-of-development" target="_blank" rel="noreferrer">https://claude.com/blog/onboarding-claude-code-like-a-new-developer-lessons-from-17-years-of-development</a></p><h3 id="summary-4" tabindex="-1">Summary <a class="header-anchor" href="#summary-4" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Brendan MacLean（MacCoss Lab）分享用人員 Onboarding 方法論管理 70 萬行 C# codebase（Skyline）。Context repository、Skills library、MCP integrations 三層架構讓 Claude 像新進開發者一樣逐步建立理解。</p><h3 id="key-points-4" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-4" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>獨立 context repository（pwiz-ai）：根目錄 CLAUDE.md + 文件指標，跨所有 branch 適用</li><li>Skills 框架：<code>skyline-development</code>、<code>version-control</code>、<code>debugging</code> 等領域知識 Skill；「參考不嵌入」保持輕量</li><li>MCP 整合（C#/Python）：連接測試結果、異常報告、支援帖，by Claude 自己撰寫</li><li>成果：原本一年的 Files View 面板專案兩週完成、2,000+ 教程截圖自動更新</li><li>原則：「將 context 視為需要維護的工件，而非一次性描述」</li></ul><hr><h2 id="meet-the-winners-of-our-built-with-opus-4-6-claude-code-hackathon" tabindex="-1">Meet the winners of our Built with Opus 4.6 Claude Code hackathon <a class="header-anchor" href="#meet-the-winners-of-our-built-with-opus-4-6-claude-code-hackathon" aria-label="Permalink to &quot;Meet the winners of our Built with Opus 4.6 Claude Code hackathon&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-20 | <strong>URL:</strong> <a href="https://claude.com/blog/meet-the-winners-of-our-built-with-opus-4-6-claude-code-hackathon" target="_blank" rel="noreferrer">https://claude.com/blog/meet-the-winners-of-our-built-with-opus-4-6-claude-code-hackathon</a></p><h3 id="summary-5" tabindex="-1">Summary <a class="header-anchor" href="#summary-5" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>5 個黑客松得獎項目，4 位非專業開發者（律師、醫師、音樂人），印證 Claude Code 的民主化影響。CrossBeam 縮短加州住宅許可審批，Elisa 讓兒童學習寫程式。</p><h3 id="key-points-5" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-5" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>CrossBeam（第一）：自動化許可審查，縮短住宅審批時間</li><li>Elisa（第二）：視覺化積木 IDE，讓兒童學習程式</li><li>PostVisit.ai（第三）：改善心臟科病患後續照護連續性</li><li>TARA：基礎設施評估，小時內完成</li><li>Conductr：以 Claude 為即時虛擬樂隊成員</li></ul><hr><h2 id="best-practices-for-using-claude-opus-4-7-with-claude-code" tabindex="-1">Best practices for using Claude Opus 4.7 with Claude Code <a class="header-anchor" href="#best-practices-for-using-claude-opus-4-7-with-claude-code" aria-label="Permalink to &quot;Best practices for using Claude Opus 4.7 with Claude Code&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-16 | <strong>URL:</strong> <a href="https://claude.com/blog/best-practices-for-using-claude-opus-4-7-with-claude-code" target="_blank" rel="noreferrer">https://claude.com/blog/best-practices-for-using-claude-opus-4-7-with-claude-code</a></p><h3 id="summary-6" tabindex="-1">Summary <a class="header-anchor" href="#summary-6" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Opus 4.7 引入 <code>xhigh</code> 預設努力等級和自適應思考（Adaptive Thinking）。強調第一輪完整給 context，減少互動次數。</p><h3 id="key-points-6" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-6" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li><code>xhigh</code> 是 agentic 編碼工作的推薦預設值</li><li>自適應思考：簡單任務跳過思考，降低 overhead</li><li>第一輪提供完整 context（意圖、限制、驗收條件、相關檔案）</li><li>行為變化：更短的預設回應、更少的工具呼叫</li></ul><hr><h2 id="using-claude-code-session-management-and-1m-context" tabindex="-1">Using Claude Code: session management and 1M context <a class="header-anchor" href="#using-claude-code-session-management-and-1m-context" aria-label="Permalink to &quot;Using Claude Code: session management and 1M context&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-15 | <strong>URL:</strong> <a href="https://claude.com/blog/using-claude-code-session-management-and-1m-context" target="_blank" rel="noreferrer">https://claude.com/blog/using-claude-code-session-management-and-1m-context</a></p><h3 id="summary-7" tabindex="-1">Summary <a class="header-anchor" href="#summary-7" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>1M token context 的管理策略：rewind/clear/compact 決策框架，context rot 防範。無關資訊累積後效能下降。</p><h3 id="key-points-7" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-7" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>使用 <code>/clear</code> 開始真正的新工作，消除過時 context</li><li>使用 <code>/rewind</code>（雙 Esc）跳回並重新 prompt</li><li>使用 <code>/compact</code> 保持連續性</li><li>為大量中間輸出的工作啟用 Subagent</li></ul><hr><h2 id="redesigning-claude-code-on-desktop-for-parallel-agents" tabindex="-1">Redesigning Claude Code on desktop for parallel agents <a class="header-anchor" href="#redesigning-claude-code-on-desktop-for-parallel-agents" aria-label="Permalink to &quot;Redesigning Claude Code on desktop for parallel agents&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-14 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-code-desktop-redesign" target="_blank" rel="noreferrer">https://claude.com/blog/claude-code-desktop-redesign</a></p><h3 id="summary-8" tabindex="-1">Summary <a class="header-anchor" href="#summary-8" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>桌面 App 全面重新設計：多 Agent 並行、drag-and-drop 版面、內建終端機、檔案編輯器和 diff 檢視器。</p><h3 id="key-points-8" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-8" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>統一 sidebar：活躍與歷史 session，支援篩選</li><li>內建終端機、檔案編輯器、diff 檢視器和預覽面板</li><li>三種檢視模式（Verbose、Normal、Summary）</li><li>SSH 支援延伸至 Mac，適用 Pro 至 Enterprise</li></ul><hr><h2 id="seeing-like-an-agent-how-we-design-tools-in-claude-code" tabindex="-1">Seeing like an agent: how we design tools in Claude Code <a class="header-anchor" href="#seeing-like-an-agent-how-we-design-tools-in-claude-code" aria-label="Permalink to &quot;Seeing like an agent: how we design tools in Claude Code&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-10 | <strong>URL:</strong> <a href="https://claude.com/blog/seeing-like-an-agent" target="_blank" rel="noreferrer">https://claude.com/blog/seeing-like-an-agent</a></p><h3 id="summary-9" tabindex="-1">Summary <a class="header-anchor" href="#summary-9" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>從 Agent 視角設計有效工具的哲學。Progressive Disclosure、約 20 個工具上限，強調實驗和觀察。</p><h3 id="key-points-9" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-9" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>從 Agent 視角思考工具設計</li><li>迭代至關重要：多次失敗後才找到 Claude 穩定採用的解法</li><li>隨模型改進，過去有用的約束會變成限制</li><li>Progressive Disclosure：透過巢狀文件逐步揭露 context</li></ul><hr><h2 id="how-and-when-to-use-subagents-in-claude-code" tabindex="-1">How and when to use subagents in Claude Code <a class="header-anchor" href="#how-and-when-to-use-subagents-in-claude-code" aria-label="Permalink to &quot;How and when to use subagents in Claude Code&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-07 | <strong>URL:</strong> <a href="https://claude.com/blog/subagents-in-claude-code" target="_blank" rel="noreferrer">https://claude.com/blog/subagents-in-claude-code</a></p><h3 id="summary-10" tabindex="-1">Summary <a class="header-anchor" href="#summary-10" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Subagent 是擁有獨立 context window 的隔離 Claude 實例。指南涵蓋何時委派（研究密集、並行、驗證）及多種呼叫方法。</p><h3 id="key-points-10" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-10" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Subagent 隔離 context，防止累積資料膨脹 token 成本</li><li>多個 Subagent 可並行執行，總時間約等於執行一個</li><li>自訂 Subagent、CLAUDE.md、Skill 和 Hook 逐步自動化委派</li><li>非所有任務適合委派：連續依賴工作在主對話處理更簡單</li></ul><hr><h2 id="auto-mode-for-claude-code" tabindex="-1">Auto mode for Claude Code <a class="header-anchor" href="#auto-mode-for-claude-code" aria-label="Permalink to &quot;Auto mode for Claude Code&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-24 | <strong>URL:</strong> <a href="https://claude.com/blog/auto-mode" target="_blank" rel="noreferrer">https://claude.com/blog/auto-mode</a></p><h3 id="summary-11" tabindex="-1">Summary <a class="header-anchor" href="#summary-11" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Auto mode 是新的權限設定，讓 Claude 獨立做出權限決策，自動阻止潛在破壞性操作，同時允許安全操作。在頻繁審批提示和繞過所有安全檢查之間取得平衡。</p><h3 id="key-points-11" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-11" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>智能分類器審查每個工具呼叫，阻止大規模刪除、數據洩漏或惡意程式碼</li><li>漸進式升級策略：安全操作自動進行，風險操作被阻止並提供替代方案</li><li>跨平台支援：桌面、VS Code、JetBrains、CLI 和 Web</li><li>管理員可透過 managed settings 停用</li></ul><hr><h2 id="product-management-on-the-ai-exponential" tabindex="-1">Product management on the AI exponential <a class="header-anchor" href="#product-management-on-the-ai-exponential" aria-label="Permalink to &quot;Product management on the AI exponential&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-19 | <strong>URL:</strong> <a href="https://claude.com/blog/product-management-on-the-ai-exponential" target="_blank" rel="noreferrer">https://claude.com/blog/product-management-on-the-ai-exponential</a></p><h3 id="summary-12" tabindex="-1">Summary <a class="header-anchor" href="#summary-12" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude Code Head of Product Cat Wu 探討快速改進的 AI 模型如何改變產品管理，從傳統長期規劃轉向快速實驗和迭代優化。</p><h3 id="key-points-12" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-12" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>角色邊界模糊：設計師寫程式、工程師做產品決策、PM 建原型</li><li>短衝刺規劃加「side quests」（自主下午實驗）取代冗長前期規劃</li><li>Demo 優先開發：原型作為主要溝通工具，而非文件</li><li>每次模型發布促使重新考慮現有功能</li></ul><hr><h2 id="code-with-claude-comes-to-san-francisco-london-and-tokyo" tabindex="-1">Code with Claude comes to San Francisco, London, and Tokyo <a class="header-anchor" href="#code-with-claude-comes-to-san-francisco-london-and-tokyo" aria-label="Permalink to &quot;Code with Claude comes to San Francisco, London, and Tokyo&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-18 | <strong>URL:</strong> <a href="https://claude.com/blog/code-with-claude-san-francisco-london-tokyo" target="_blank" rel="noreferrer">https://claude.com/blog/code-with-claude-san-francisco-london-tokyo</a></p><h3 id="summary-13" tabindex="-1">Summary <a class="header-anchor" href="#summary-13" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>開發者大會 Code with Claude 擴展至三個全球城市。全天活動包含實作工作坊、產品示範和與 Anthropic 工程師的直接互動。</p><h3 id="key-points-13" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-13" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>舊金山（5/6）、倫敦（5/19）、東京（6/10）</li><li>含 workshop、最新功能示範、與 Anthropic 的 1:1 office hours</li><li>有限現場名額（隨機抽選），另有直播和錄影</li></ul><hr><h2 id="bringing-code-review-to-claude-code" tabindex="-1">Bringing Code Review to Claude Code <a class="header-anchor" href="#bringing-code-review-to-claude-code" aria-label="Permalink to &quot;Bringing Code Review to Claude Code&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-09 | <strong>URL:</strong> <a href="https://claude.com/blog/code-review" target="_blank" rel="noreferrer">https://claude.com/blog/code-review</a></p><h3 id="summary-14" tabindex="-1">Summary <a class="header-anchor" href="#summary-14" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>AI 驅動的多 Agent code review 系統。54% 的 PR 收到實質性評論（對比以前的 16%），大型 PR 平均發現 7.5 個問題，每次 $15-25。</p><h3 id="key-points-14" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-14" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>多 Agent 平行審查：驗證發現以消除誤報，依嚴重性排序問題</li><li>54% PR 收到實質性評論 vs 16%；不到 1% 的發現被標記錯誤</li><li>實際影響：發現關鍵認證 bug 和生產系統的預存在類型不符</li><li>月度費用上限和 repository 級控制進行成本管理</li></ul><hr><h2 id="improving-skill-creator-test-measure-and-refine-agent-skills" tabindex="-1">Improving skill-creator: Test, measure, and refine Agent Skills <a class="header-anchor" href="#improving-skill-creator-test-measure-and-refine-agent-skills" aria-label="Permalink to &quot;Improving skill-creator: Test, measure, and refine Agent Skills&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-03 | <strong>URL:</strong> <a href="https://claude.com/blog/improving-skill-creator-test-measure-and-refine-agent-skills" target="_blank" rel="noreferrer">https://claude.com/blog/improving-skill-creator-test-measure-and-refine-agent-skills</a></p><h3 id="summary-15" tabindex="-1">Summary <a class="header-anchor" href="#summary-15" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Skill-creator 新增測試和基準評測能力，讓 Skill 作者可驗證正確性並隨時間優化效能。包含評估框架、多 Agent 並行測試和自動描述優化。</p><h3 id="key-points-15" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-15" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>評估框架：作者可撰寫預期輸出測試，捕捉回歸</li><li>基準模式：標準化評估追蹤模型更新後的通過率、時間和 token 用量</li><li>多 Agent 並行測試：在隔離 context 中同時執行評估</li><li>比較 Agent：在 Skill 版本或 Skill vs 基準線之間進行 A/B 測試</li></ul><hr><h2 id="how-ai-helps-break-the-cost-barrier-to-cobol-modernization" tabindex="-1">How AI helps break the cost barrier to COBOL modernization <a class="header-anchor" href="#how-ai-helps-break-the-cost-barrier-to-cobol-modernization" aria-label="Permalink to &quot;How AI helps break the cost barrier to COBOL modernization&quot;">​</a></h2><p><strong>Date:</strong> 2026-02-23 | <strong>URL:</strong> <a href="https://claude.com/blog/how-ai-helps-break-cost-barrier-cobol-modernization" target="_blank" rel="noreferrer">https://claude.com/blog/how-ai-helps-break-cost-barrier-cobol-modernization</a></p><h3 id="summary-16" tabindex="-1">Summary <a class="header-anchor" href="#summary-16" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>COBOL 系統支撐全球關鍵基礎設施，但現代化成本一直高得令人望而卻步。Claude Code 自動化複雜分析階段，讓組織能在數季而非數年內完成現代化。</p><h3 id="key-points-16" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-16" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>COBOL 挑戰：95% 的美國 ATM 交易依賴 COBOL，退休開發者帶走機構知識</li><li>自動化程式碼分析：跨數千行映射依賴關係，識別隱式數據流</li><li>風險評估：識別高耦合組件 vs 可早期現代化的隔離模組</li><li>增量驗證：逐組件現代化，每個階段測試，防止大規模回滾</li></ul><hr><h2 id="bringing-automated-preview-review-and-merge-to-claude-code-on-desktop" tabindex="-1">Bringing automated preview, review, and merge to Claude Code on desktop <a class="header-anchor" href="#bringing-automated-preview-review-and-merge-to-claude-code-on-desktop" aria-label="Permalink to &quot;Bringing automated preview, review, and merge to Claude Code on desktop&quot;">​</a></h2><p><strong>Date:</strong> 2026-02-20 | <strong>URL:</strong> <a href="https://claude.com/blog/preview-review-and-merge-with-claude-code" target="_blank" rel="noreferrer">https://claude.com/blog/preview-review-and-merge-with-claude-code</a></p><h3 id="summary-17" tabindex="-1">Summary <a class="header-anchor" href="#summary-17" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude Code 桌面版新增即時應用預覽、自動化 code review 和 GitHub PR 管理（含自動修復和合併功能）。讓開發者在單一介面完成從實作到部署的完整工作流。</p><h3 id="key-points-17" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-17" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>即時應用預覽：啟動開發服務器，實時錯誤偵測和 console log 監控</li><li>整合 code review：Claude 審查本地變更，提供內嵌評論、bug 識別和建議</li><li>GitHub PR 管理：監控 CI 狀態，可選自動修復和自動合併</li><li>背景 PR 監控：開發者工作時 Claude Code 繼續追蹤 PR 狀態</li></ul><hr><h2 id="a-complete-guide-to-building-skills-for-claude" tabindex="-1">A complete guide to building skills for Claude <a class="header-anchor" href="#a-complete-guide-to-building-skills-for-claude" aria-label="Permalink to &quot;A complete guide to building skills for Claude&quot;">​</a></h2><p><strong>Date:</strong> 2026-01-29 | <strong>URL:</strong> <a href="https://claude.com/blog/complete-guide-to-building-skills-for-claude" target="_blank" rel="noreferrer">https://claude.com/blog/complete-guide-to-building-skills-for-claude</a></p><h3 id="summary-18" tabindex="-1">Summary <a class="header-anchor" href="#summary-18" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>幫助開發者、MCP 建置者和高級用戶建立 Skill 的綜合指南。涵蓋技術需求、測試策略和分發方法，15-30 分鐘即可完成第一個有效 Skill。</p><h3 id="key-points-18" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-18" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Skill 結構和要求：有效可重用工作流模板的技術基礎</li><li>MCP 整合模式：將 Skill 與 MCP 連接器結合</li><li>測試和迭代方法：在分發前驗證 Skill</li><li>分發和部署策略：組織內和更廣 Claude 社群的共享</li></ul><hr><h2 id="understand-claude-code-s-impact-with-contribution-metrics" tabindex="-1">Understand Claude Code&#39;s impact with contribution metrics <a class="header-anchor" href="#understand-claude-code-s-impact-with-contribution-metrics" aria-label="Permalink to &quot;Understand Claude Code&#39;s impact with contribution metrics&quot;">​</a></h2><p><strong>Date:</strong> 2026-01-29 | <strong>URL:</strong> <a href="https://claude.com/blog/contribution-metrics" target="_blank" rel="noreferrer">https://claude.com/blog/contribution-metrics</a></p><h3 id="summary-19" tabindex="-1">Summary <a class="header-anchor" href="#summary-19" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Anthropic 為 Claude Code 引入貢獻指標，追蹤 PR 合併和代碼提交。內部數據顯示每位工程師每天合併的 PR 增加 67%，70-90% 的代碼現在使用 Claude Code 協助撰寫。</p><h3 id="key-points-19" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-19" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>GitHub 整合：自動顯示 PR 建立、代碼提交和每位用戶採用模式</li><li>保守測量：只計算有高度信心是 Claude Code 相關的代碼</li><li>速度影響：每位工程師每天合併 PR 增加 67%</li><li>適用 Team 和 Enterprise 客戶，需安裝 GitHub App</li></ul>',142)])])}const p=a(i,[["render",l]]);export{m as __pageData,p as default};
